SELECT category, atc_code 
FROM pharmaceuticals
WHERE who_rec_list = 1;

SELECT category, COUNT(*) AS count 
FROM pharmaceuticals 
GROUP BY category;

SELECT category 
FROM pharmaceuticals
WHERE LENGTH(category) = (SELECT MIN(LENGTH(category)) FROM pharmaceuticals);

SELECT 
    (SELECT COUNT(*) FROM pharmaceuticals) AS total_pharmaceuticals,
    (SELECT COUNT(*) FROM countries) AS total_countries;
